import{c as n,S as h,j as a,m as t}from"./chunks/framework.8aa1YH_s.js";const p=JSON.parse('{"title":"Hỏi đáp với giáo viên","description":"","frontmatter":{},"headers":[],"relativePath":"hoc-vien/hoi-dap.md","filePath":"hoc-vien/hoi-dap.md","lastUpdated":0}'),o={name:"hoc-vien/hoi-dap.md"};function c(l,i,u,g,r,e){return h(),a("div",null,[...i[0]||(i[0]=[t('<h1 id="hoi-đap-voi-giao-vien" tabindex="-1">Hỏi đáp với giáo viên <a class="header-anchor" href="#hoi-đap-voi-giao-vien" aria-label="Permalink to “Hỏi đáp với giáo viên”">​</a></h1><p>Chức năng Hỏi đáp giúp bạn <strong>hỏi giáo viên trực tiếp</strong> khi gặp khó khăn trong học tập, không cần đợi buổi học live.</p><h2 id="ban-co-the-hoi-tu-đau" tabindex="-1">Bạn có thể hỏi từ đâu? <a class="header-anchor" href="#ban-co-the-hoi-tu-đau" aria-label="Permalink to “Bạn có thể hỏi từ đâu?”">​</a></h2><h3 id="_1-duoi-bai-giang" tabindex="-1">1. Dưới bài giảng <a class="header-anchor" href="#_1-duoi-bai-giang" aria-label="Permalink to “1. Dưới bài giảng”">​</a></h3><ul><li>Trong khi học video / bài giảng, có khung <strong>Hỏi đáp</strong> bên dưới.</li><li>Hỏi cụ thể về nội dung bài đó.</li></ul><h3 id="_2-sau-cau-hoi-sai" tabindex="-1">2. Sau câu hỏi sai <a class="header-anchor" href="#_2-sau-cau-hoi-sai" aria-label="Permalink to “2. Sau câu hỏi sai”">​</a></h3><ul><li>Khi <a href="./xem-lai-bai-thi">xem lại bài thi</a>, mỗi câu có nút <strong>Hỏi giáo viên</strong>.</li><li>Hỏi về cách giải, đáp án nếu không hiểu.</li></ul><h3 id="_3-khu-thao-luan-cua-khoa" tabindex="-1">3. Khu Thảo luận của khóa <a class="header-anchor" href="#_3-khu-thao-luan-cua-khoa" aria-label="Permalink to “3. Khu Thảo luận của khóa”">​</a></h3><ul><li>Trong khóa của bạn → tab <strong>Thảo luận</strong> (chung cho cả khóa).</li><li>Phù hợp với câu hỏi tổng quát (vd &quot;Phương pháp ôn HSA trong 1 tháng&quot;).</li></ul><h3 id="_4-hoi-đap-tong-neu-he-thong-co" tabindex="-1">4. Hỏi đáp tổng (nếu hệ thống có) <a class="header-anchor" href="#_4-hoi-đap-tong-neu-he-thong-co" aria-label="Permalink to “4. Hỏi đáp tổng (nếu hệ thống có)”">​</a></h3><ul><li>Trang Hỏi đáp dùng chung - thảo luận với cộng đồng + giáo viên.</li></ul><h2 id="đat-cau-hoi-tot" tabindex="-1">Đặt câu hỏi tốt <a class="header-anchor" href="#đat-cau-hoi-tot" aria-label="Permalink to “Đặt câu hỏi tốt”">​</a></h2><h3 id="cau-truc-khuyen-nghi" tabindex="-1">Cấu trúc khuyến nghị <a class="header-anchor" href="#cau-truc-khuyen-nghi" aria-label="Permalink to “Cấu trúc khuyến nghị”">​</a></h3><ol><li><p><strong>Tiêu đề / 1 câu mô tả vấn đề</strong>: &quot;Em không hiểu vì sao đáp án câu 12 trong đề HSA Đợt 1 là B.&quot;</p></li><li><p><strong>Mô tả chi tiết</strong>: &quot;Em làm theo cách... [nêu cách]. Em ra đáp án D. Em không hiểu chỗ nào em sai.&quot;</p></li><li><p><strong>Đính kèm</strong> (nếu cần):</p><ul><li>Ảnh chụp đề / bài làm tay</li><li>File scan</li><li>Link đến câu hỏi cụ thể</li></ul></li><li><p><strong>Kỳ vọng</strong>: &quot;Mong thầy/cô chỉ giúp em chỗ sai.&quot;</p></li></ol><h3 id="tranh" tabindex="-1">Tránh <a class="header-anchor" href="#tranh" aria-label="Permalink to “Tránh”">​</a></h3><div class="warning custom-block"><p class="custom-block-title">Câu hỏi quá chung</p><p>&quot;Em làm đề HSA điểm thấp, có cách nào học tốt hơn không thầy?&quot; → Quá rộng. Hỏi cụ thể: &quot;Em sai 8/10 câu phần Đại số, có lộ trình nào ôn riêng phần này không?&quot;</p></div><div class="warning custom-block"><p class="custom-block-title">Hỏi đáp án mà không nỗ lực</p><p>&quot;Câu này đáp án là gì thầy?&quot; → Không học được gì. Hãy hỏi &quot;Em nghĩ là B vì... có đúng không thầy?&quot;</p></div><h2 id="theo-doi-cau-hoi-cua-ban" tabindex="-1">Theo dõi câu hỏi của bạn <a class="header-anchor" href="#theo-doi-cau-hoi-cua-ban" aria-label="Permalink to “Theo dõi câu hỏi của bạn”">​</a></h2><ul><li>Vào <strong>Hồ sơ → Tab Câu hỏi của tôi</strong>.</li><li>Hoặc ở mỗi vị trí hỏi, có <strong>Lịch sử câu hỏi của bạn ở đây</strong>.</li></ul><h3 id="trang-thai-cau-hoi" tabindex="-1">Trạng thái câu hỏi <a class="header-anchor" href="#trang-thai-cau-hoi" aria-label="Permalink to “Trạng thái câu hỏi”">​</a></h3><ul><li><strong>Chờ trả lời</strong> (vừa gửi)</li><li><strong>Đã trả lời</strong> (giáo viên đã phản hồi)</li><li><strong>Đã đóng</strong> (giáo viên đóng sau khi giải đáp xong)</li></ul><h3 id="thong-bao" tabindex="-1">Thông báo <a class="header-anchor" href="#thong-bao" aria-label="Permalink to “Thông báo”">​</a></h3><ul><li>Khi giáo viên trả lời → bạn nhận <strong>push / email</strong>.</li><li>Vào câu hỏi → đọc phản hồi → nếu cần, <strong>hỏi tiếp</strong> trong cùng luồng.</li></ul><h2 id="tiep-tuc-thao-luan" tabindex="-1">Tiếp tục thảo luận <a class="header-anchor" href="#tiep-tuc-thao-luan" aria-label="Permalink to “Tiếp tục thảo luận”">​</a></h2><ul><li>Trong luồng câu hỏi, gõ ô <strong>Trả lời</strong> để hỏi thêm.</li><li>Mỗi câu hỏi có thể có <strong>nhiều lượt qua lại</strong> giữa bạn và giáo viên.</li></ul><h2 id="xem-cau-hoi-cua-ban-khac" tabindex="-1">Xem câu hỏi của bạn khác <a class="header-anchor" href="#xem-cau-hoi-cua-ban-khac" aria-label="Permalink to “Xem câu hỏi của bạn khác”">​</a></h2><p>Nếu chế độ công khai (do giáo viên cấu hình):</p><ul><li>Bạn thấy câu hỏi của các học viên khác cùng khóa.</li><li>Đôi khi câu của người khác cũng là <strong>câu của bạn</strong> - đọc đáp án có sẵn còn nhanh hơn hỏi mới.</li><li>Có thể <strong>like / vote</strong> câu hỏi hữu ích.</li></ul><h2 id="meo-dung-hoi-đap-hieu-qua" tabindex="-1">Mẹo dùng Hỏi đáp hiệu quả <a class="header-anchor" href="#meo-dung-hoi-đap-hieu-qua" aria-label="Permalink to “Mẹo dùng Hỏi đáp hiệu quả”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Hỏi sớm, đừng để dồn</p><ul><li>Học mỗi ngày 1 ít, hỏi mỗi ngày 1 ít.</li><li>Đừng dồn 50 câu hỏi lúc gần thi - sẽ không kịp tiếp thu.</li></ul></div><div class="tip custom-block"><p class="custom-block-title">Tìm câu trả lời sẵn trước</p><ul><li>Có ô tìm kiếm trong khu Hỏi đáp.</li><li>Khả năng cao câu của bạn đã có người hỏi và được trả lời.</li></ul></div><div class="tip custom-block"><p class="custom-block-title">Tham gia thảo luận</p><ul><li>Trả lời câu của bạn khác (nếu bạn biết) - vừa giúp người, vừa củng cố kiến thức.</li><li>Giáo viên thường xếp hạng &quot;Học viên tích cực&quot; → ưu tiên trả lời câu của họ.</li></ul></div><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Bao lâu giáo viên trả lời?</strong> → Thường trong <strong>24 giờ làm việc</strong>. Câu phức tạp có thể lâu hơn. Nếu quá lâu, đặt câu hỏi nhắc nhẹ hoặc liên hệ trung tâm.</p><p><strong>Tôi gửi câu hỏi nhưng không thấy trong danh sách?</strong> → Tải lại trang, kiểm tra đăng nhập đúng tài khoản. Nếu vẫn không có, có thể bị lọc spam - liên hệ trung tâm.</p><p><strong>Có thể gửi câu hỏi ẩn danh không?</strong> → Mặc định <strong>có hiển thị tên</strong> (trong khu thảo luận khóa). Hỏi riêng giáo viên thì chỉ giáo viên thấy tên.</p><p><strong>Tôi không thấy giáo viên trả lời câu hỏi cũ.</strong> → Có thể câu hỏi đã được đóng. Đặt câu hỏi mới với context rõ ràng.</p><p><strong>Tôi muốn tag 1 giáo viên cụ thể.</strong> → Trong khu thảo luận khóa, dùng <code>@tên_giáo_viên</code> (nếu hệ thống hỗ trợ mention).</p>',38)])])}const d=n(o,[["render",c]]);export{p as __pageData,d as default};
